class Solution {
    public int minSwapsCouples(int[] row) {
        int swaps = 0;
        for (int i = 0; i < row.length; i += 2) {
            int current = row[i];
            int target = current ^ 1;
            if (row[i + 1] != target) {
                int j;
                for (j = i + 1; j < row.length; j++) {
                    if (row[j] == target) {
                        break;
                    }
                }
                // Swap row[i+1] and row[j]
                int temp = row[i + 1];
                row[i + 1] = row[j];
                row[j] = temp;
                swaps++;
            }
        }
        return swaps;
    }
}

